3209 /// If the pair of operators are the same invertible function, return the
3210 /// the operands of the function corresponding to each input. Otherwise,
3211 /// return std::nullopt.  An invertible function is one that is 1-to-1 and maps
3212 /// every input value to exactly one output value.  This is equivalent to
3213 /// saying that Op1 and Op2 are equal exactly when the specified pair of
3214 /// operands are equal, (except that Op1 and Op2 may be poison more often.)
3215 static std::optional<std::pair<Value*, Value*>>
3216 getInvertibleOperands(const Operator *Op1,
3217                       const Operator *Op2) {
3218   if (Op1->getOpcode() != Op2->getOpcode())
3219     return std::nullopt;
3220 
3221   auto getOperands = [&](unsigned OpNum) -> auto {
3222     return std::make_pair(Op1->getOperand(OpNum), Op2->getOperand(OpNum));
3223   };
3224 
3225   switch (Op1->getOpcode()) {
3226   default:
3227     break;
3228   case Instruction::Or:
3229     if (!cast<PossiblyDisjointInst>(Op1)->isDisjoint() ||
3230         !cast<PossiblyDisjointInst>(Op2)->isDisjoint())
3231       break;
3232     [[fallthrough]];
3233   case Instruction::Xor:
3234   case Instruction::Add: {
3235     Value *Other;
3236     if (match(Op2, m_c_BinOp(m_Specific(Op1->getOperand(0)), m_Value(Other))))
3237       return std::make_pair(Op1->getOperand(1), Other);
3238     if (match(Op2, m_c_BinOp(m_Specific(Op1->getOperand(1)), m_Value(Other))))
3239       return std::make_pair(Op1->getOperand(0), Other);
3240     break;
3241   }
3242   case Instruction::Sub:
3243     if (Op1->getOperand(0) == Op2->getOperand(0))
3244       return getOperands(1);
3245     if (Op1->getOperand(1) == Op2->getOperand(1))
3246       return getOperands(0);
3247     break;
3248   case Instruction::Mul: {
3249     // invertible if A * B == (A * B) mod 2^N where A, and B are integers
3250     // and N is the bitwdith.  The nsw case is non-obvious, but proven by
3251     // alive2: https://alive2.llvm.org/ce/z/Z6D5qK
3252     auto *OBO1 = cast<OverflowingBinaryOperator>(Op1);
3253     auto *OBO2 = cast<OverflowingBinaryOperator>(Op2);
3254     if ((!OBO1->hasNoUnsignedWrap() || !OBO2->hasNoUnsignedWrap()) &&
3255         (!OBO1->hasNoSignedWrap() || !OBO2->hasNoSignedWrap()))
3256       break;
3257 
3258     // Assume operand order has been canonicalized
3259     if (Op1->getOperand(1) == Op2->getOperand(1) &&
3260         isa<ConstantInt>(Op1->getOperand(1)) &&
3261         !cast<ConstantInt>(Op1->getOperand(1))->isZero())
3262       return getOperands(0);
3263     break;
3264   }
3265   case Instruction::Shl: {
3266     // Same as multiplies, with the difference that we don't need to check
3267     // for a non-zero multiply. Shifts always multiply by non-zero.
3268     auto *OBO1 = cast<OverflowingBinaryOperator>(Op1);
3269     auto *OBO2 = cast<OverflowingBinaryOperator>(Op2);
3270     if ((!OBO1->hasNoUnsignedWrap() || !OBO2->hasNoUnsignedWrap()) &&
3271         (!OBO1->hasNoSignedWrap() || !OBO2->hasNoSignedWrap()))
3272       break;
3273 
3274     if (Op1->getOperand(1) == Op2->getOperand(1))
3275       return getOperands(0);
3276     break;
3277   }
3278   case Instruction::AShr:
3279   case Instruction::LShr: {
3280     auto *PEO1 = cast<PossiblyExactOperator>(Op1);
3281     auto *PEO2 = cast<PossiblyExactOperator>(Op2);
3282     if (!PEO1->isExact() || !PEO2->isExact())
3283       break;
3284 
3285     if (Op1->getOperand(1) == Op2->getOperand(1))
3286       return getOperands(0);
3287     break;
3288   }
3289   case Instruction::SExt:
3290   case Instruction::ZExt:
3291     if (Op1->getOperand(0)->getType() == Op2->getOperand(0)->getType())
3292       return getOperands(0);
3293     break;
3294   case Instruction::PHI: {
3295     const PHINode *PN1 = cast<PHINode>(Op1);
3296     const PHINode *PN2 = cast<PHINode>(Op2);
3297 
3298     // If PN1 and PN2 are both recurrences, can we prove the entire recurrences
3299     // are a single invertible function of the start values? Note that repeated
3300     // application of an invertible function is also invertible
3301     BinaryOperator *BO1 = nullptr;
3302     Value *Start1 = nullptr, *Step1 = nullptr;
3303     BinaryOperator *BO2 = nullptr;
3304     Value *Start2 = nullptr, *Step2 = nullptr;
3305     if (PN1->getParent() != PN2->getParent() ||
3306         !matchSimpleRecurrence(PN1, BO1, Start1, Step1) ||
3307         !matchSimpleRecurrence(PN2, BO2, Start2, Step2))
3308       break;
3309 
3310     auto Values = getInvertibleOperands(cast<Operator>(BO1),
3311                                         cast<Operator>(BO2));
3312     if (!Values)
3313        break;
3314 
3315     // We have to be careful of mutually defined recurrences here.  Ex:
3316     // * X_i = X_(i-1) OP Y_(i-1), and Y_i = X_(i-1) OP V
3317     // * X_i = Y_i = X_(i-1) OP Y_(i-1)
3318     // The invertibility of these is complicated, and not worth reasoning
3319     // about (yet?).
3320     if (Values->first != PN1 || Values->second != PN2)
3321       break;
3322 
3323     return std::make_pair(Start1, Start2);
3324   }
3325   }
3326   return std::nullopt;
3327 }
